mapper.insert:
INSERT INTO post (
    user_id, mode_type, category, title, content, image_path
)
VALUES (
    #{userId}, #{modeType}, #{category}, #{title}, #{content}, #{imagePath}
)

mapper.update:
UPDATE post
SET is_deleted = 1
WHERE post_id = #{postId}

UPDATE post
SET like_count = like_count + #{amount}
WHERE post_id = #{postId}

UPDATE post
SET scrap_count = scrap_count + #{amount}
WHERE post_id = #{postId}

UPDATE post
SET comment_count = comment_count + #{amount}
WHERE post_id = #{postId}

mapper.select:
SELECT COUNT(*)
FROM post_like
WHERE post_id = #{postId}
  AND user_id = #{userId}

mapper.delete:
DELETE FROM post_like
WHERE post_id = #{postId}
  AND user_id = #{userId}

